const heatPumpFaqs: FAQ[] = [
  { id: 'hp-1', question: 'What is a heat pump water heater?', answer: 'A heat pump water heater uses refrigerant and a compressor to extract heat from ambient air and transfer it to water, making it 3–4× more energy-efficient than a conventional electric resistance heater.' },
  { id: 'hp-2', question: 'How does a heat pump water heater work?', answer: 'It works like a refrigerator in reverse: a fan draws in ambient air, the refrigerant absorbs heat from that air, the compressor amplifies the heat, and the condenser coil transfers it to the water tank.' },
  { id: 'hp-3', question: 'How energy-efficient is a V-Guard heat pump?', answer: 'V-Guard heat pumps carry a COP (Coefficient of Performance) of 3.0–4.5, meaning every 1 kWh of electricity produces 3–4.5 kWh of heat energy — saving up to 70% on water-heating bills.' },
  { id: 'hp-4', question: 'What is the ideal ambient temperature for operation?', answer: 'Most models operate optimally between 10°C and 43°C. They can still function below 10°C in hybrid mode but efficiency drops slightly.' },
  { id: 'hp-5', question: 'Can a heat pump work in cold climates?', answer: 'Yes. Modern heat pumps have a backup electric heating element that activates when ambient temperature falls below a threshold, ensuring hot water year-round.' },
  { id: 'hp-6', question: 'What size heat pump do I need for my home?', answer: 'A family of 4 typically needs a 200–250 L unit. Larger families or commercial setups may require 300–500 L models. Our team at Jal Urja Solutions can help size the right unit.' },
  { id: 'hp-7', question: 'How long does installation take?', answer: 'A standard residential installation takes 4–6 hours. The unit needs adequate ventilation space (minimum 1,000 cubic feet) and a dedicated electrical connection.' },
  { id: 'hp-8', question: 'Where should a heat pump water heater be installed?', answer: 'Install it in a well-ventilated area such as a utility room, garage, or outdoor covered space. Avoid sealed, unventilated cupboards as the unit needs airflow to extract heat.' },
  { id: 'hp-9', question: 'Does it make noise during operation?', answer: 'Heat pumps produce 50–60 dB of operating noise — similar to a running dishwasher. Install away from bedrooms if noise sensitivity is a concern.' },
  { id: 'hp-10', question: 'What is the warranty on V-Guard heat pumps?', answer: 'V-Guard offers a 2-year comprehensive warranty on the unit and a 5-year warranty on the compressor. Jal Urja Solutions provides local after-sales support in Nashik.' },
  { id: 'hp-11', question: 'How often does it require maintenance?', answer: 'Annual servicing is recommended: clean the air filter every 3 months, inspect the refrigerant circuit yearly, and flush the tank every 2 years to prevent scale build-up.' },
  { id: 'hp-12', question: 'Can a heat pump be connected to solar panels?', answer: 'Yes. Pairing a heat pump with solar PV panels can reduce operating costs to near-zero. A 1–1.5 kW solar system is generally sufficient to run the compressor during the day.' },
  { id: 'hp-13', question: 'What is the average lifespan of a heat pump water heater?', answer: 'With proper maintenance, V-Guard heat pumps last 12–15 years, significantly longer than conventional electric geysers.' },
  { id: 'hp-14', question: 'How long does it take to heat a full tank?', answer: 'A 200 L tank heated from 15°C to 55°C typically takes 2–3 hours in heat pump mode. The backup element can provide faster recovery if needed.' },
  { id: 'hp-15', question: 'Is it safe to use hard water with a heat pump?', answer: 'Hard water can cause scale on the heat exchanger. A scale inhibitor cartridge or water softener is recommended if your TDS is above 300 ppm — ask us about Zero B water treatment solutions.' },
  { id: 'hp-16', question: 'What is the difference between heat pump and solar water heater?', answer: 'Solar heaters use sunlight directly and produce no heat on cloudy days. Heat pumps use ambient air and work 24/7 regardless of sunshine, making them more reliable in monsoon seasons.' },
  { id: 'hp-17', question: 'Do heat pumps work during load shedding?', answer: 'No — they require electricity. However, their high efficiency means they can charge a full tank quickly when power is available, and a well-insulated tank retains heat for 12–24 hours.' },
  { id: 'hp-18', question: 'What electrical requirements are needed?', answer: 'Most residential units need a 15A, 230V single-phase supply. Larger commercial units (above 500 L) may need a three-phase supply.' },
  { id: 'hp-19', question: 'Can I integrate a heat pump with an existing plumbing system?', answer: 'Yes. V-Guard heat pumps have standard BSP pipe fittings and can connect to your existing plumbing. Our technicians will assess compatibility during installation.' },
  { id: 'hp-20', question: 'What is the BEE star rating on V-Guard heat pumps?', answer: 'V-Guard heat pump models carry a 5-star BEE rating, qualifying for subsidy schemes under the National Energy Efficiency Initiatives.' },
  { id: 'hp-21', question: 'Is there a government subsidy for heat pump water heaters in India?', answer: 'Yes. MNRE and several state energy departments provide subsidies on heat pump water heaters. Contact us for up-to-date subsidy information applicable in Nashik / Maharashtra.' },
  { id: 'hp-22', question: 'Can the heat pump be used for space heating?', answer: 'The models we stock are water-heating specific. For space heating or HVAC heat pumps, contact us for a custom recommendation.' },
  { id: 'hp-23', question: 'What refrigerant is used and is it eco-friendly?', answer: 'V-Guard heat pumps use R32 or R410A refrigerant. R32 has a lower Global Warming Potential (GWP) than older refrigerants and is the industry standard for green heat pumps.' },
  { id: 'hp-24', question: 'What happens if the compressor fails?', answer: 'The backup electric element continues to heat water while the compressor is repaired. Contact our service team — V-Guard\'s 5-year compressor warranty covers replacement costs.' },
  { id: 'hp-25', question: 'Where can I buy a V-Guard heat pump in Nashik?', answer: 'Avegatasta Jal Urja Solutions is an authorised V-Guard distributor in Nashik. Visit us or send a WhatsApp inquiry for pricing, availability, and installation.' },
  { id: 'hp-26', question: 'Does operating in humid conditions affect performance?', answer: 'Humid conditions actually improve heat pump efficiency as moist air carries more heat energy. Coastal or monsoon climates are well-suited for heat pump operation.' },
];

const solarWaterHeaterFaqs: FAQ[] = [
  { id: 'sw-1', question: 'How does a solar water heater work?', answer: 'Solar water heaters use flat plate or evacuated tube collectors to absorb sunlight and transfer the heat to water circulating through the system, storing it in an insulated tank.' },
  { id: 'sw-2', question: 'What are evacuated tube collectors?', answer: 'Evacuated tube collectors consist of rows of glass tubes with a vacuum between the outer and inner layers. The vacuum eliminates heat loss, making them highly efficient even on cloudy days.' },
  { id: 'sw-3', question: 'What is a flat plate collector?', answer: 'A flat plate collector is an insulated metal box with a dark absorber plate and glass cover. More affordable than evacuated tubes, it works best in sunny regions with low-to-moderate hot water demand.' },
  { id: 'sw-4', question: 'How much does a solar water heater save on electricity bills?', answer: 'A well-sized solar heater can cut water-heating costs by 60–80%, saving ₹3,000–₹8,000 annually for an average family depending on usage and sunlight availability.' },
  { id: 'sw-5', question: 'What capacity solar water heater do I need?', answer: 'The standard rule is 50–75 litres per person. A family of 4 needs a 200–300 L system. Commercial setups (hotels, hostels) may need 500 L+ multi-panel systems.' },
  { id: 'sw-6', question: 'Does it work on cloudy days?', answer: 'Evacuated tube systems can still produce hot water at reduced efficiency on overcast days. All our systems include an electric backup element for consistently hot water regardless of weather.' },
  { id: 'sw-7', question: 'What orientation and tilt is needed for installation?', answer: 'Collectors should face true south (in India) at a tilt angle equal to the site\'s latitude ±15°. For Nashik (20°N), a 20–35° tilt is optimal.' },
  { id: 'sw-8', question: 'Is my roof suitable for solar water heater installation?', answer: 'RCC, tiled, and metal sheet roofs all support solar heaters. The collector adds 30–60 kg/m² load — our engineers assess structural suitability before installation.' },
  { id: 'sw-9', question: 'How long does a solar water heater last?', answer: 'Quality systems last 15–20 years. The collector panels are the longest-lasting component; the tank and backup element may need replacement at 10–12 years with regular maintenance.' },
  { id: 'sw-10', question: 'What maintenance is required?', answer: 'Clean the collector glass every 1–2 months (more often in dusty areas), flush the tank annually, and check the backup element and valves yearly.' },
  { id: 'sw-11', question: 'Is hard water a problem for solar water heaters?', answer: 'Yes. Scale deposits on the heat exchanger reduce efficiency. A descaling treatment every 2 years and a pre-filtration system are recommended in hard water areas like Nashik.' },
  { id: 'sw-12', question: 'What is the payback period?', answer: 'Most residential systems pay back their cost in 3–5 years through electricity savings and MNRE subsidies. Commercial systems often pay back in 2–3 years.' },
  { id: 'sw-13', question: 'Is there a government subsidy available?', answer: 'MNRE provides a 30% capital subsidy on solar water heaters in many states. Maharashtra-specific schemes also offer additional benefits. Contact us for current scheme details.' },
  { id: 'sw-14', question: 'Can a solar heater be used for industrial processes?', answer: 'Yes. We supply industrial-grade solar thermal systems for food processing, dairy, hospital, and hospitality applications. Get in touch for a custom quote.' },
  { id: 'sw-15', question: 'What happens at night or during extended cloudy periods?', answer: 'The integrated electric backup element automatically switches on to maintain the set temperature, ensuring uninterrupted hot water supply.' },
  { id: 'sw-16', question: 'What is natural circulation (thermosiphon) vs forced circulation?', answer: 'Thermosiphon systems rely on natural convection (the tank must be above the collector). Forced circulation uses a pump for flexibility in tank placement and better efficiency in large systems.' },
  { id: 'sw-17', question: 'Can solar water heaters be used in high-rise apartments?', answer: 'Yes, with rooftop installations and adequate pipe insulation. Forced circulation systems work best for multi-storey buildings to overcome pressure and height differences.' },
  { id: 'sw-18', question: 'How is the water pressure in a solar water heater?', answer: 'Thermosiphon systems operate at gravity pressure (1–2 bar). Pressurised systems are available for homes with high-pressure plumbing requirements.' },
  { id: 'sw-19', question: 'What is the warranty on solar water heaters?', answer: 'Collector panels typically carry a 5-year warranty; tanks 3–5 years; backup elements 1–2 years. Exact terms vary by brand and model — ask us for specifics.' },
  { id: 'sw-20', question: 'Can I connect solar hot water to my shower, kitchen, and tap?', answer: 'Yes. The solar storage tank feeds into your home\'s hot water plumbing and can supply all hot water points simultaneously.' },
  { id: 'sw-21', question: 'Will a solar heater work in Nashik\'s climate?', answer: 'Nashik has excellent solar irradiance (5–6 kWh/m²/day on average) and is well-suited for solar water heating for most of the year.' },
  { id: 'sw-22', question: 'What is a freeze protection valve and do I need one?', answer: 'Freeze protection valves drain water from the collector when temperatures approach freezing. Nashik rarely experiences freezing temperatures, so this is generally unnecessary here.' },
  { id: 'sw-23', question: 'Are solar water heaters eco-friendly?', answer: 'Yes. They reduce CO₂ emissions by 1.5–2 tonnes per year compared to electric geysers. The carbon payback period is typically less than 1 year.' },
  { id: 'sw-24', question: 'Can I add more collector panels later to increase capacity?', answer: 'Yes. Most systems are modular and allow adding panels or upgrading the storage tank as your hot water needs grow.' },
  { id: 'sw-25', question: 'Where can I buy solar water heaters in Nashik?', answer: 'Jal Urja Solutions is your authorised distributor in Nashik. We supply, install, and service solar water heaters. Contact us via WhatsApp or the inquiry form on this page.' },
  { id: 'sw-26', question: 'What size pipe is recommended for solar water heater installation?', answer: '15 mm (1/2 inch) CPVC or copper pipes are standard for residential systems. Larger commercial systems may use 25 mm lines for adequate flow.' },
];

const domesticPumpFaqs: FAQ[] = [
  { id: 'dp-1', question: 'What is a domestic water pump?', answer: 'A domestic water pump is an electrically powered pump designed to boost water pressure and supply water from a sump or underground tank to overhead tanks and fixtures in a home.' },
  { id: 'dp-2', question: 'What is the difference between a centrifugal pump and a self-priming pump?', answer: 'Centrifugal pumps need to be primed (water-filled) before starting and are used when the water source is at or above the pump level. Self-priming pumps can draw water from below without manual priming, making them more convenient for domestic use.' },
  { id: 'dp-3', question: 'How do I choose the right pump capacity?', answer: 'Consider total head (vertical height + friction losses) and flow rate required. For a 2-storey home, a pump with 1–1.5 HP and 35–45 m head is typically sufficient. Our team can help size accurately.' },
  { id: 'dp-4', question: 'What is "total head" in pump selection?', answer: 'Total head is the sum of the vertical height the pump lifts water plus friction losses in pipes. It determines how powerful a pump you need for your plumbing layout.' },
  { id: 'dp-5', question: 'Can I use a domestic pump for borewell water?', answer: 'Standard domestic pumps are not suitable for borewells. Submersible pumps or deep-well pumps are designed for that application. We stock V-Guard submersible pumps too.' },
  { id: 'dp-6', question: 'What is the difference between 0.5 HP, 1 HP, and 1.5 HP pumps?', answer: '0.5 HP suits single-storey homes with low demand. 1 HP handles 2-storey buildings and moderate flow. 1.5 HP is for large homes, 3+ storeys, or high-head applications.' },
  { id: 'dp-7', question: 'What is ISI certification and why does it matter?', answer: 'ISI (BIS IS 8034) certification ensures the pump meets Indian standard quality and safety requirements. V-Guard pumps carry ISI marks on key models, guaranteeing reliability.' },
  { id: 'dp-8', question: 'How long do domestic pumps last?', answer: 'Well-maintained V-Guard pumps last 8–12 years. Key factors are regular servicing, clean water source, and protection against dry running and voltage fluctuations.' },
  { id: 'dp-9', question: 'Can the pump run dry?', answer: 'Running dry damages the mechanical seal and impeller. Use a dry-run protection relay or float switch on your sump to automatically cut power when water level is low.' },
  { id: 'dp-10', question: 'What voltage fluctuation can V-Guard pumps handle?', answer: 'Standard models operate on 230V ±10%. Wide-voltage or VG-Guard variants handle 160–270V, making them suitable for areas with unstable power supply.' },
  { id: 'dp-11', question: 'How do I install a domestic pump?', answer: 'Mount it on a vibration-damping pad, connect suction and delivery pipes with PTFE-sealed joints, wire through a dedicated MCB, and prime before first start. Professional installation is recommended.' },
  { id: 'dp-12', question: 'What pipe size should I use with the pump?', answer: 'Match the pipe diameter to the pump\'s inlet/outlet port (typically 1 inch to 1.5 inch). Avoid reducing pipe size on the suction side as it causes cavitation.' },
  { id: 'dp-13', question: 'Why is my pump noisy?', answer: 'Common causes: cavitation (insufficient inlet water), air in the system, worn bearings, or a loose impeller. Have a technician diagnose if the noise is new or sudden.' },
  { id: 'dp-14', question: 'Why does the pump start and stop frequently (short cycling)?', answer: 'Short cycling is usually caused by a waterlogged pressure tank, faulty pressure switch, or a leak in the delivery line. Check and re-pressurise the expansion tank if fitted.' },
  { id: 'dp-15', question: 'Do V-Guard pumps come with a warranty?', answer: 'Yes — standard 12-month warranty. Extended warranty options are available. Jal Urja Solutions provides authorised warranty service in Nashik.' },
  { id: 'dp-16', question: 'Can I use an automatic pressure switch?', answer: 'Yes. Automatic pressure switches start the pump when line pressure drops (tap opened) and stop it when pressure is restored, eliminating the need to manually switch the pump.' },
  { id: 'dp-17', question: 'Is an inverter/UPS compatible with domestic pumps?', answer: 'Yes, if the inverter VA rating exceeds 3× the pump\'s full load current (starting surge). A 1 HP pump typically needs a 2 kVA inverter minimum.' },
  { id: 'dp-18', question: 'What is an aluminium vs cast iron pump body?', answer: 'Aluminium bodies are lightweight and corrosion-resistant, ideal for most domestic applications. Cast iron bodies offer greater strength and durability for heavier-duty use.' },
  { id: 'dp-19', question: 'Can a domestic pump work with a solar power system?', answer: 'AC pumps need an inverter with the solar system. DC solar pumps are also available for off-grid setups where running wiring for an inverter is impractical.' },
  { id: 'dp-20', question: 'How do I prime a centrifugal pump?', answer: 'Fill the pump casing and suction pipe completely with water through the priming plug on top, close the priming plug, then start the pump. Never start without priming.' },
  { id: 'dp-21', question: 'What causes low water pressure at taps despite the pump running?', answer: 'Possible causes: undersized pump for the head/flow required, partially closed valve, air lock in the line, worn impeller, or blocked suction strainer. Have it inspected.' },
  { id: 'dp-22', question: 'How much electricity does a 1 HP pump consume?', answer: 'A 1 HP (0.75 kW) pump running 2 hours per day consumes approximately 1.5 kWh/day or ~45 kWh/month, costing around ₹270–₹360 at ₹6–₹8/unit.' },
  { id: 'dp-23', question: 'What is thermal overload protection?', answer: 'A built-in thermal relay cuts power to the motor if it overheats due to prolonged operation or blockage, protecting the winding from burn-out.' },
  { id: 'dp-24', question: 'Can I use a domestic pump for garden irrigation?', answer: 'Yes. A self-priming centrifugal pump with adequate pressure is suitable for drip or sprinkler irrigation. Check that the flow rate matches your irrigation system\'s requirements.' },
  { id: 'dp-25', question: 'Where can I buy V-Guard domestic pumps in Nashik?', answer: 'Avegatasta Jal Urja Solutions is an authorised V-Guard dealer in Nashik. We stock the full range — VC Series, Snow Series, Blue Series, and more. Visit us or send an inquiry.' },
  { id: 'dp-26', question: 'What is the return policy if the pump is defective?', answer: 'Defective units within 7 days of purchase can be exchanged through us. Warranty repairs and replacements are handled at our service centre in Nashik.' },
];

const pumpingSegmentFaqs: FAQ[] = [
  { id: 'ps-1', question: 'What are pumping segments?', answer: 'Pumping segments refer to specialised pump categories for agricultural, industrial, and infrastructure applications — including submersible, openwell, borewell, and turbine pumps for large-scale or high-head pumping.' },
  { id: 'ps-2', question: 'What types of pumps are available for agriculture?', answer: 'V-Guard and Wilo offer centrifugal monoblock pumps, submersible pumps, and surface pumps designed for irrigation canals, open wells, and bore holes.' },
  { id: 'ps-3', question: 'How do I choose between a submersible pump and a monoblock pump?', answer: 'Use a submersible pump when water must be lifted from a deep borewell (20 m+). Use a monoblock pump for shallow wells, sumps, or surface water sources within 8 m suction depth.' },
  { id: 'ps-4', question: 'What is a monoblock pump?', answer: 'A monoblock pump has the motor and pump in a single unit, making it compact, easy to install, and low-maintenance. Suitable for irrigation and water supply up to 8 m suction lift.' },
  { id: 'ps-5', question: 'What is the maximum depth a submersible pump can operate?', answer: 'V-Guard submersible pumps are available for depths up to 150–200 m depending on the model. Motor and column pipe selection must match the depth.' },
  { id: 'ps-6', question: 'What is column pipe and how is it sized?', answer: 'Column pipe is the pipe connecting the submersible pump to the surface. Size (diameter and wall thickness) depends on flow rate, depth, and operating pressure — our engineers size this correctly for your bore.' },
  { id: 'ps-7', question: 'Can submersible pumps handle sandy water?', answer: 'Standard submersible pumps can handle minor silt. Heavily sandy water requires sand-fighter or abrasion-resistant models to prevent premature wear of the impeller and diffuser.' },
  { id: 'ps-8', question: 'What is a star-delta starter and when is it needed?', answer: 'A star-delta starter reduces the starting current of motors above 5 HP, preventing voltage dips and protecting the motor. Required for most agricultural pump motors above 5 HP.' },
  { id: 'ps-9', question: 'What is a VFD (Variable Frequency Drive) and how does it help?', answer: 'A VFD controls motor speed to match actual demand, saving 20–40% energy in variable-flow applications like irrigation or municipal water supply compared to fixed-speed pumps.' },
  { id: 'ps-10', question: 'What is the role of a pump controller or panel?', answer: 'A pump control panel provides overload protection, phase failure protection, dry-run protection, and remote/auto start-stop. Essential for unattended operation in agricultural or industrial settings.' },
  { id: 'ps-11', question: 'What is the difference between open impeller and closed impeller?', answer: 'Open impellers handle fibrous or dirty water better. Closed impellers are more efficient for clean water and high-pressure applications. Choose based on your water quality.' },
  { id: 'ps-12', question: 'How often should industrial/agricultural pumps be serviced?', answer: 'Annual preventive maintenance is recommended: check mechanical seals, bearings, impeller wear, motor insulation, and electrical connections. More frequent service for continuous-duty applications.' },
  { id: 'ps-13', question: 'What protection does a submersible motor need?', answer: 'Submersible motors require adequate water flow around the motor for cooling. A flow inducer sleeve is used when the borewell casing is larger than the motor to ensure coolant flow.' },
  { id: 'ps-14', question: 'What causes water hammer and how is it prevented?', answer: 'Water hammer is pressure surge when flow suddenly stops (pump trip or valve closure). Non-return (check) valves and slow-closing valves dampen the surge and protect pipework.' },
  { id: 'ps-15', question: 'Can Wilo pumps be used for fire-fighting systems?', answer: 'Yes. Wilo manufactures dedicated fire-fighting pump sets compliant with IS 12524. Contact us for jockey pump, main pump, and diesel-backup pump configurations.' },
  { id: 'ps-16', question: 'What is a jockey pump?', answer: 'A jockey (pressure maintenance) pump maintains pressure in a fire hydrant system and starts automatically when small leaks or test flows drop system pressure, preventing the main pump from starting unnecessarily.' },
  { id: 'ps-17', question: 'How do I calculate pump power requirements?', answer: 'Power (kW) = (Flow in m³/h × Head in m) / (367 × pump efficiency). Our engineers size pumps precisely to avoid over-sizing (wasted energy) or under-sizing (inadequate performance).' },
  { id: 'ps-18', question: 'What is NPSH and why does it matter?', answer: 'NPSH (Net Positive Suction Head) is the minimum pressure required at the pump inlet to prevent cavitation. Always ensure system NPSH available > pump NPSH required, especially for high-lift applications.' },
  { id: 'ps-19', question: 'Can pumping systems be solar-powered?', answer: 'Yes. Solar-powered pumping systems (DC or AC + inverter) are available for remote irrigation and water supply. MNRE provides subsidies under the PM KUSUM scheme for solar pump sets.' },
  { id: 'ps-20', question: 'What is a multistage pump?', answer: 'A multistage pump has multiple impeller stages in series to build high pressure with modest flow — ideal for high-rise buildings, RO systems, and boiler feed applications.' },
  { id: 'ps-21', question: 'What is the difference between horizontal and vertical pumps?', answer: 'Horizontal pumps are easier to install and maintain. Vertical turbine and submersible pumps are used when the pump must be positioned below the water source or inside a borewell.' },
  { id: 'ps-22', question: 'Can Wilo pumps be used for HVAC chilled water circulation?', answer: 'Yes. Wilo\'s inline and close-coupled centrifugal pumps are widely used for HVAC chilled and hot water loops, with high efficiency and quiet operation.' },
  { id: 'ps-23', question: 'What is pump affinity law and why does it matter for energy saving?', answer: 'The affinity law states that reducing pump speed by 20% cuts power consumption by ~50%. This underpins the energy savings possible with VFD-controlled pumps.' },
  { id: 'ps-24', question: 'What are typical industries served by Wilo pumps?', answer: 'Wilo pumps serve water treatment, HVAC, fire-fighting, building services, agriculture, industrial process, mining, and municipal water supply sectors.' },
  { id: 'ps-25', question: 'How do I get a custom pumping system designed for my project?', answer: 'Contact Jal Urja Solutions with your project requirements: flow rate, head, water quality, and operating hours. We provide engineering, supply, installation, and commissioning of complete pumping systems.' },
  { id: 'ps-26', question: 'What is the typical delivery time for large pump orders?', answer: 'Stock items ship within 3–5 days. Custom-configured industrial pump sets may take 3–6 weeks. Contact us early for project planning.' },
];

const waterTreatmentFaqs: FAQ[] = [
  { id: 'wt-1', question: 'What is TDS and why does it matter in drinking water?', answer: 'TDS (Total Dissolved Solids) measures dissolved minerals and salts in water. The WHO guideline for drinking water is below 500 mg/L; Zero B RO systems reduce TDS to the ideal range of 100–200 mg/L.' },
  { id: 'wt-2', question: 'What is the difference between RO, UV, and UF purifiers?', answer: 'RO (Reverse Osmosis) removes dissolved salts, heavy metals, and bacteria. UV kills bacteria and viruses without removing minerals. UF is a membrane filter removing bacteria and cysts without electricity. Many modern purifiers combine all three.' },
  { id: 'wt-3', question: 'What is a water softener and when do I need one?', answer: 'A water softener removes calcium and magnesium ions that cause hardness, scaling in pipes/geysers, and skin issues. Recommended when water hardness exceeds 200 ppm as CaCO₃.' },
  { id: 'wt-4', question: 'How does a Zero B RO system work?', answer: 'Mains water is pre-filtered to remove sediment and chlorine, then forced through a semi-permeable RO membrane that rejects dissolved salts and contaminants, storing purified water in a pressurised tank.' },
  { id: 'wt-5', question: 'How much water does an RO system waste?', answer: 'Conventional RO systems reject 2–3 L for every 1 L purified. Zero B\'s High Recovery models reduce this to 1:1 or better, saving significant water especially in a water-scarce region like Nashik.' },
  { id: 'wt-6', question: 'What is the service life of an RO membrane?', answer: 'RO membranes typically last 2–3 years depending on feed water quality and usage. Regular pre-filter changes protect the membrane and extend its life.' },
  { id: 'wt-7', question: 'How often do I need to change the filters?', answer: 'Sediment and carbon pre-filters: every 6 months. Post-carbon polishing filter: every 12 months. RO membrane: every 2–3 years. Zero B service plans ensure timely replacements.' },
  { id: 'wt-8', question: 'Is Zero B an authorised brand?', answer: 'Yes. Avegatasta Jal Urja Solutions is an authorised Zero B distributor in Nashik. All products come with genuine warranty and certified service support.' },
  { id: 'wt-9', question: 'Can an RO system remove fluoride from water?', answer: 'Yes. RO membranes reject 85–95% of fluoride. If fluoride is a concern in your area\'s water supply, an RO system is the most effective point-of-use treatment.' },
  { id: 'wt-10', question: 'Does an RO system remove beneficial minerals?', answer: 'Yes — RO removes most minerals including calcium and magnesium. Zero B\'s mineraliser/TDS controller re-adds essential minerals back to the purified water for taste and health.' },
  { id: 'wt-11', question: 'What is a TDS controller in a water purifier?', answer: 'A TDS controller blends a small portion of untreated water with RO-purified water to add back essential minerals, adjusting the final TDS to a healthy and palatable level.' },
  { id: 'wt-12', question: 'How do I test my water quality before choosing a purifier?', answer: 'We offer a free water quality test at Jal Urja Solutions. Testing measures TDS, hardness, pH, bacteriological load, and common contaminants to recommend the right purification system.' },
  { id: 'wt-13', question: 'What is the minimum water pressure required for an RO system?', answer: 'Most RO systems need 7–10 psi (0.5–0.7 bar). A booster pump is included in Zero B systems to handle low municipal supply pressure.' },
  { id: 'wt-14', question: 'Can a water purifier work without electricity?', answer: 'UF (Ultrafiltration) membrane purifiers work on gravity or municipal water pressure without electricity. UV and RO systems require power. For power-outage areas, gravity-based UF units are a good backup.' },
  { id: 'wt-15', question: 'What is descaling and when is it needed?', answer: 'Descaling removes mineral scale (calcium carbonate deposits) from RO membranes, tanks, and fittings using a dilute acid solution. It\'s done during annual servicing or when flow rate drops noticeably.' },
  { id: 'wt-16', question: 'Can I install an RO system for my entire house?', answer: 'Whole-house RO systems are available but expensive and waste more water. The more common and cost-effective approach is a point-of-use RO for drinking/cooking only.' },
  { id: 'wt-17', question: 'What is a water softener\'s salt consumption?', answer: 'A typical household ion-exchange softener uses 4–8 kg of sodium chloride salt per regeneration cycle, which occurs every 7–10 days. Annual salt cost is approximately ₹2,000–₹4,000.' },
  { id: 'wt-18', question: 'Is softened water safe to drink?', answer: 'Ion-exchange softened water contains elevated sodium levels and is generally not recommended for drinking by those on low-sodium diets. Treat drinking water with a separate RO/UV system.' },
  { id: 'wt-19', question: 'What warranty do Zero B products carry?', answer: 'Zero B offers 1-year comprehensive warranty on the unit. Extended AMC (Annual Maintenance Contract) packages covering all filter and membrane replacements are available through us.' },
  { id: 'wt-20', question: 'Can Zero B purifiers be wall-mounted?', answer: 'Yes. Most Zero B under-counter and wall-mounted RO systems come with standard mounting hardware. Our installation team sets it up neatly under your kitchen sink or on the wall.' },
  { id: 'wt-21', question: 'What is the storage capacity of a typical RO purifier?', answer: 'Residential Zero B models have 8–12 L storage tanks. When the tank is full, a float valve automatically shuts off the RO pump until water is used.' },
  { id: 'wt-22', question: 'What is the difference between sediment filter and activated carbon filter?', answer: 'A sediment filter (PP cartridge) removes suspended particles, sand, and rust. An activated carbon filter removes chlorine, organic chemicals, and bad taste/odour before water reaches the RO membrane.' },
  { id: 'wt-23', question: 'How can I tell if my purifier needs servicing?', answer: 'Signs include reduced water flow, change in taste or smell, indicator light alarm, or TDS reading above the desired level. Schedule service with us proactively every 6 months to avoid these issues.' },
  { id: 'wt-24', question: 'Do you offer AMC (Annual Maintenance Contracts) in Nashik?', answer: 'Yes. Jal Urja Solutions offers Zero B AMC plans covering all consumable replacements, labour, and priority service calls. Contact us for plan pricing.' },
  { id: 'wt-25', question: 'Where can I buy Zero B water purifiers in Nashik?', answer: 'Avegatasta Jal Urja Solutions is your authorised Zero B dealer in Nashik. We supply, install, and service the complete range. Contact us via WhatsApp or the inquiry form.' },
];

const swimmingPoolFaqs: FAQ[] = [
  { id: 'sp-1', question: 'What equipment is needed to maintain a swimming pool?', answer: 'Core equipment includes a circulation pump, sand/cartridge filter, chlorinator/dosing system, skimmer, underwater lights, and a pool vacuum. We supply and install complete Bluewave India pool systems.' },
  { id: 'sp-2', question: 'How often should pool water be tested?', answer: 'Test water 2–3 times per week during the swimming season: check free chlorine (1–3 ppm), pH (7.2–7.6), alkalinity (80–120 ppm), and calcium hardness (200–400 ppm).' },
  { id: 'sp-3', question: 'What is the ideal chlorine level for a swimming pool?', answer: 'Free chlorine should be maintained at 1–3 ppm for residential pools and 1–5 ppm for commercial pools. Levels below 1 ppm risk bacterial growth; above 5 ppm causes eye and skin irritation.' },
  { id: 'sp-4', question: 'What is pH and why is it important in pool water?', answer: 'pH measures acidity/alkalinity on a 0–14 scale. The ideal pool pH is 7.2–7.6. High pH reduces chlorine effectiveness; low pH corrodes equipment and irritates swimmers\' eyes and skin.' },
  { id: 'sp-5', question: 'How does a sand filter work for a swimming pool?', answer: 'Pool water is pushed through a tank of specially graded silica sand. Particles as small as 20 microns are trapped; clean water returns to the pool. Backwashing reverses flow to flush trapped debris.' },
  { id: 'sp-6', question: 'How often should I backwash the sand filter?', answer: 'Backwash when the filter pressure gauge reads 7–10 psi above the clean start-up pressure, or at least once per week during heavy use. Each backwash takes 2–3 minutes.' },
  { id: 'sp-7', question: 'What is a pool pump\'s turnover rate?', answer: 'Turnover rate is the time to circulate the entire pool volume through the filter. Aim for a complete turnover every 6–8 hours (run the pump 8–12 hours/day for a residential pool).' },
  { id: 'sp-8', question: 'What is total alkalinity in pool water?', answer: 'Total alkalinity (80–120 ppm) buffers pH swings, keeping water balanced. Low alkalinity causes rapid pH fluctuation; high alkalinity makes pH resistant to correction.' },
  { id: 'sp-9', question: 'What is "shocking" or super-chlorination?', answer: 'Shocking means adding a large dose of chlorine (calcium hypochlorite or liquid chlorine) to eliminate chloramines, algae, and bacteria — typically after heavy use, rainstorms, or visible algae.' },
  { id: 'sp-10', question: 'How do I prevent algae in my pool?', answer: 'Maintain proper chlorine and pH levels, run the pump sufficiently, brush pool walls weekly, and add a preventive algaecide monthly. Green algae can overtake a pool in 24–48 hours if chemistry is off.' },
  { id: 'sp-11', question: 'What chemicals are used in pool water treatment?', answer: 'Common chemicals include chlorine (disinfectant), pH plus/minus (pH adjustment), alkalinity increaser, calcium hardness increaser, algaecide, clarifier, and stabiliser (cyanuric acid).' },
  { id: 'sp-12', question: 'What is cyanuric acid (stabiliser) and how much is needed?', answer: 'Cyanuric acid stabilises chlorine against UV degradation, extending its lifespan in outdoor pools. Maintain 30–50 ppm; above 100 ppm it reduces chlorine effectiveness ("chlorine lock").' },
  { id: 'sp-13', question: 'How often should I replace pool water?', answer: 'Residential pools rarely need complete replacement if chemistry is maintained. Partial replacement (20–30%) every 2–3 years helps dilute accumulated stabiliser and dissolved solids.' },
  { id: 'sp-14', question: 'What size pump do I need for my pool?', answer: 'Size the pump to turn over the full pool volume in 8 hours. For a 50,000 L pool: 50,000 / 8 / 60 = ~104 L/min. Choose a pump and filter rated above that flow.' },
  { id: 'sp-15', question: 'What is a salt chlorinator and how does it work?', answer: 'A salt chlorinator electrolyses dissolved salt (NaCl) in pool water to generate chlorine continuously, eliminating the need to buy and handle chlorine chemicals. Maintain salt at 2,500–4,000 ppm.' },
  { id: 'sp-16', question: 'Are salt water pools better than chlorine pools?', answer: 'Salt pools produce a gentler, more consistent chlorine level that is less irritating to eyes and skin. Equipment cost is higher upfront, but ongoing chemical costs are lower.' },
  { id: 'sp-17', question: 'What is a pool skimmer?', answer: 'A skimmer is a surface-level opening in the pool wall that draws floating debris (leaves, insects, sunscreen) into the filtration system before it sinks, keeping the pool surface clean.' },
  { id: 'sp-18', question: 'How do I choose pool underwater lights?', answer: 'LED underwater lights offer 50,000+ hour life and low energy consumption vs halogen. Choose colour-changing RGB LED for ambiance or single-colour white/blue for simplicity. Ensure IP68 waterproofing.' },
  { id: 'sp-19', question: 'Can a swimming pool be heated?', answer: 'Yes. Heat pump water heaters, solar pool heaters, and gas heaters are all options. Heat pumps offer the best energy efficiency for year-round heated pools in India\'s climate.' },
  { id: 'sp-20', question: 'Do you supply equipment for commercial pools?', answer: 'Yes. Jal Urja Solutions supplies Bluewave India and other commercial-grade pool equipment for hotels, resorts, clubs, and public pools. We also provide turnkey installation and commissioning.' },
  { id: 'sp-21', question: 'What is a pool vacuum and how is it used?', answer: 'A pool vacuum is a cleaning head connected via hose to the skimmer suction. It removes settled debris from the floor and walls. Robotic automatic cleaners are also available for hands-free cleaning.' },
  { id: 'sp-22', question: 'How do I winterise a pool (if closed seasonally)?', answer: 'Lower water level, balance chemistry, add winteriser algaecide and chlorine, blow out and plug lines, cover the pool with a winter cover, and remove and store pumps if temperatures drop below freezing.' },
  { id: 'sp-23', question: 'What is the warranty on Bluewave India pool products?', answer: 'Bluewave India offers 1–2 year warranties depending on the product. Pumps and filters typically carry 1-year parts warranty; LED lights carry 2 years. Jal Urja Solutions handles local warranty claims.' },
  { id: 'sp-24', question: 'What chemicals should I never mix when treating pool water?', answer: 'Never mix chlorine and acid directly — they react violently. Always add chemicals separately to the pool water (never to each other), and allow circulation between additions.' },
  { id: 'sp-25', question: 'Where can I buy pool equipment in Nashik?', answer: 'Avegatasta Jal Urja Solutions stocks Bluewave India pool pumps, filters, chemicals, lights, and accessories in Nashik. Contact us for pricing, installation, and ongoing maintenance support.' },
  { id: 'sp-26', question: 'How do I maintain pool water clarity?', answer: 'Maintain proper chlorine and pH, run the pump 8–12 hours daily, backwash regularly, brush walls weekly, and use a clarifier (flocculant) when water appears hazy despite correct chemistry.' },
];

const waterHeaterFaqs: FAQ[] = [
  { id: 'wh-1', question: 'What types of electric water heaters are available?', answer: 'V-Guard offers storage water heaters (tank type, 6–25 L), instant geysers (1–3 L), and heat pump water heaters. Storage geysers maintain temperature continuously; instant geysers heat on demand.' },
  { id: 'wh-2', question: 'What capacity water heater do I need?', answer: 'A single person needs 6–10 L. A couple needs 10–15 L. A family of 4 needs 15–25 L for a storage geyser. For continuous/large-family use, a heat pump (100–200 L) is more economical.' },
  { id: 'wh-3', question: 'What is the difference between a storage geyser and an instant water heater?', answer: 'Storage geysers heat and store water at a set temperature, ready for use anytime. Instant heaters heat water on demand as it flows through — better for low-volume use like hand washing.' },
  { id: 'wh-4', question: 'What wattage are V-Guard electric geysers?', answer: 'V-Guard storage geysers have 2,000 W elements. Instant geysers are typically 3,000 W. Higher wattage heats water faster but draws more instantaneous current — ensure your wiring and MCB are rated accordingly.' },
  { id: 'wh-5', question: 'How long does it take to heat water in a storage geyser?', answer: 'A 15 L geyser typically heats from 20°C to 65°C in 15–25 minutes with a 2,000 W element. An 8 L geyser heats in about 8–12 minutes.' },
  { id: 'wh-6', question: 'What is glass-lined inner tank and why does it matter?', answer: 'A glass-lined (vitreous enamel) tank resists corrosion far better than a plain steel tank. Combined with a sacrificial magnesium anode rod, it prevents rust and extends tank life significantly.' },
  { id: 'wh-7', question: 'What is a magnesium anode rod and when should it be replaced?', answer: 'A magnesium anode rod attracts corrosive minerals, protecting the steel tank from rusting. It should be inspected every 2–3 years and replaced when worn more than 50% — typically every 3–5 years.' },
  { id: 'wh-8', question: 'What safety certifications should a water heater have?', answer: 'Look for BIS IS 302/IS 1350 certification and a safety valve (pressure relief valve), thermostat, and thermal cut-out. V-Guard geysers carry all required Indian safety certifications.' },
  { id: 'wh-9', question: 'What is the thermostat setting on a water heater?', answer: 'Most geysers have adjustable thermostats set between 35°C and 75°C. 55–60°C is recommended to kill legionella bacteria while avoiding scalding risk and excessive energy use.' },
  { id: 'wh-10', question: 'How much electricity does a water heater consume?', answer: 'A 15 L geyser used once daily at full capacity uses approximately 1 kWh/day, about ₹6–₹8/day at current rates. Running the thermostat lower and insulating the unit reduces consumption.' },
  { id: 'wh-11', question: 'Should I turn the geyser off when not in use?', answer: 'Yes — switching off when not in use saves 15–30% energy. Use a timer or smart switch to automatically heat water 30 minutes before your routine morning use.' },
  { id: 'wh-12', question: 'What BEE star rating should I look for?', answer: 'Choose a 5-star BEE-rated geyser for maximum energy efficiency. V-Guard\'s Pebble and Sprinhot series are available in 5-star variants with superior insulation to minimise standby losses.' },
  { id: 'wh-13', question: 'Can a water heater be installed outdoors?', answer: 'Standard geysers are for indoor, dry-area installation. If installation near a wet area or outdoor balcony is needed, ensure the unit has an IP25+ ingress protection rating.' },
  { id: 'wh-14', question: 'What pipe connections are needed for geyser installation?', answer: 'Geysers need a cold water inlet, hot water outlet, safety valve, and a drain line. Use CPVC or copper pipe for hot water connections — PVC may warp under repeated high temperatures.' },
  { id: 'wh-15', question: 'How is the safety valve on a geyser tested?', answer: 'Manually lift the safety valve lever briefly once a month to check it opens freely and closes without leaking. A stuck or leaking safety valve should be replaced immediately.' },
  { id: 'wh-16', question: 'Can a water heater be used with a solar water heater?', answer: 'Yes. The geyser can act as a backup booster for the solar system, only activating its element when the solar-heated water temperature falls below the thermostat set-point.' },
  { id: 'wh-17', question: 'What warranty does V-Guard offer on water heaters?', answer: 'V-Guard offers a 2-year comprehensive warranty on the electrical components and a 5-year warranty on the inner tank. Jal Urja Solutions provides warranty service in Nashik.' },
  { id: 'wh-18', question: 'What causes scale build-up in a geyser?', answer: 'Hard water (high calcium and magnesium content) deposits scale on the heating element and tank walls over time, reducing efficiency and eventually causing element failure. Descale annually if your water is hard.' },
  { id: 'wh-19', question: 'How do I descale an electric water heater?', answer: 'Drain the tank, fill with a dilute citric acid or descaling solution, let it soak for 4–6 hours, drain and flush completely before refilling. Annual descaling is recommended for hard water areas.' },
  { id: 'wh-20', question: 'What is the difference between horizontal and vertical geyser installation?', answer: 'Vertical installation is standard and most space-efficient. Horizontal installation is used under low-clearance surfaces or in specific cabinet configurations. Most V-Guard models support both orientations.' },
  { id: 'wh-21', question: 'Is there a risk of electric shock with a geyser?', answer: 'A properly grounded geyser with a functioning ELCB (Earth Leakage Circuit Breaker) at the distribution board eliminates shock risk. Never use a geyser without proper earthing.' },
  { id: 'wh-22', question: 'What is the ideal water pressure for a storage geyser?', answer: 'Standard geysers are rated for 6–8 bar maximum working pressure. Ensure your municipal supply pressure does not exceed this — fit a pressure reducing valve if supply pressure is high.' },
  { id: 'wh-23', question: 'Can I use a water heater with a solar or inverter power supply?', answer: 'Most 2,000 W geysers need a 3–4 kVA inverter to run. This is high consumption for an inverter battery — it is generally more practical to heat water before a power cut rather than run on backup.' },
  { id: 'wh-24', question: 'How do I know when to replace my water heater?', answer: 'Indicators: rust-coloured water, visible tank corrosion, persistent leaks, element burning out repeatedly, or the unit being over 8–10 years old. At this point replacement is more economical than repair.' },
  { id: 'wh-25', question: 'Where can I buy V-Guard water heaters in Nashik?', answer: 'Avegatasta Jal Urja Solutions is an authorised V-Guard dealer in Nashik. We stock storage geysers, instant geysers, and heat pump water heaters with professional installation service.' },
];

const electricMotorFaqs: FAQ[] = [
  { id: 'em-1', question: 'What types of electric motors are available?', answer: 'V-Guard offers single-phase induction motors (fractional to 3 HP) for domestic and light commercial use, and three-phase induction motors for industrial and agricultural applications up to 200+ HP.' },
  { id: 'em-2', question: 'What is the difference between single-phase and three-phase motors?', answer: 'Single-phase motors run on standard 230V domestic supply. Three-phase motors use 415V 3-phase industrial supply and are more efficient, smoother-running, and available in larger power ratings.' },
  { id: 'em-3', question: 'What is motor efficiency class (IE1, IE2, IE3)?', answer: 'IE1 is standard efficiency; IE2 is high efficiency; IE3 is premium efficiency. IE3 motors consume 3–6% less energy than IE1 motors — significant savings for continuously-running industrial motors.' },
  { id: 'em-4', question: 'What is motor insulation class and why does it matter?', answer: 'Insulation class (B, F, H) defines the maximum temperature the winding insulation can handle. Class F (155°C) is standard for most applications; Class H (180°C) for high-ambient-temperature environments.' },
  { id: 'em-5', question: 'What is the IP (Ingress Protection) rating of electric motors?', answer: 'IP rating indicates protection against dust and water. IP23 is standard for protected indoor installation. IP55 or IP65 is required for outdoor, dusty, or wet environments like agriculture or food processing.' },
  { id: 'em-6', question: 'What is a motor\'s service factor?', answer: 'Service factor (SF) is the permissible overload ratio. An SF of 1.15 means the motor can handle 15% overload continuously without damage, providing a safety margin for peak loads.' },
  { id: 'em-7', question: 'What is the starting current of an electric motor?', answer: 'Induction motors draw 5–7× their full load current at startup. For a 5 HP motor, starting current can be 30–45A — size your MCB and wiring for the starting surge, not just running current.' },
  { id: 'em-8', question: 'When do I need a DOL vs star-delta starter?', answer: 'DOL (Direct-On-Line) is suitable for motors up to 5 HP. For motors above 5 HP, a star-delta starter reduces starting current to 1/3, preventing voltage dips and protecting equipment.' },
  { id: 'em-9', question: 'What is a Variable Frequency Drive (VFD) and when should I use it?', answer: 'A VFD controls motor speed by varying supply frequency, saving 20–50% energy in variable-load applications like fans, pumps, and compressors. Payback period is typically 1–2 years.' },
  { id: 'em-10', question: 'What causes motor overheating?', answer: 'Causes include overloading, low voltage, phase imbalance, blocked ventilation, high ambient temperature, or excessive starting frequency. Always ensure adequate cooling airflow around the motor.' },
  { id: 'em-11', question: 'How do I protect a motor from dry-run damage when driving a pump?', answer: 'Use a dry-run protection relay or flow switch that cuts motor power when the pump loses prime or source water runs out. V-Guard motor control panels include this protection.' },
  { id: 'em-12', question: 'What maintenance do electric motors require?', answer: 'Grease bearings per manufacturer schedule (every 3–6 months for standard bearings), check insulation resistance annually, inspect terminals for corrosion, clean air vents, and check for vibration or unusual noise.' },
  { id: 'em-13', question: 'What is the typical lifespan of an electric motor?', answer: 'A well-maintained motor lasts 15–20 years. Bearing failure (50% of motor failures), winding insulation breakdown, and rotor issues are the primary causes of premature failure.' },
  { id: 'em-14', question: 'What causes bearing failure in motors?', answer: 'Causes: over-greasing or under-greasing, contamination, misalignment, excessive belt tension, electrical fluting from VFD-induced currents, or operating outside rated speed range.' },
  { id: 'em-15', question: 'What is motor winding resistance and why is it tested?', answer: 'Winding resistance testing identifies shorted turns or open circuits. Insulation resistance (IR) testing (megger test) measures insulation quality — below 1 MΩ indicates a failing motor winding.' },
  { id: 'em-16', question: 'Can electric motors be rewound?', answer: 'Yes. Motors can be rewound when the stator winding fails. Rewinding by a qualified shop is cost-effective for large motors; smaller motors (below 1 HP) are often more economically replaced.' },
  { id: 'em-17', question: 'What is the difference between foot-mounted and flange-mounted motors?', answer: 'Foot-mounted motors sit on a flat base plate (B3 mounting). Flange-mounted motors bolt directly to machinery such as pump casings (B5/B14 mounting). Both configurations are available in V-Guard range.' },
  { id: 'em-18', question: 'What is TEFC (Totally Enclosed Fan Cooled) motor?', answer: 'A TEFC motor has a sealed housing with no cooling air path inside the frame. An external fan on the shaft provides cooling — making it suitable for dusty, wet, or corrosive environments.' },
  { id: 'em-19', question: 'How do I size a motor for my application?', answer: 'Calculate required shaft power based on load torque and speed. Add a 10–20% service factor margin. Avoid oversizing as motors run less efficiently at partial load.' },
  { id: 'em-20', question: 'What is power factor and how does it affect motor running cost?', answer: 'Power factor (PF) is the ratio of useful (active) power to apparent power. Low PF increases reactive current, raising line losses and electricity demand charges. V-Guard motors maintain PF above 0.80 at full load.' },
  { id: 'em-21', question: 'Can I use a single-phase motor with a VFD?', answer: 'Most VFDs are designed for three-phase motors. Single-phase motor VFD options exist but are limited. For variable-speed single-phase applications, consider a three-phase motor with a single-to-three-phase VFD.' },
  { id: 'em-22', question: 'What is frame size and why does it matter?', answer: 'Frame size (e.g., D90, D100) defines shaft height and mounting dimensions per IEC or NEMA standards. Matching frame size ensures a drop-in replacement without modifying the machine base.' },
  { id: 'em-23', question: 'How do I check if a motor is correctly aligned?', answer: 'Use a dial gauge or laser alignment tool to check angular and parallel misalignment between motor and driven machine shafts. Misalignment above 0.05 mm causes premature bearing failure and vibration.' },
  { id: 'em-24', question: 'What is the warranty on V-Guard electric motors?', answer: 'V-Guard offers 12-month warranty on standard motors. Extended warranty options are available. Jal Urja Solutions provides authorised warranty service and spare parts in Nashik.' },
  { id: 'em-25', question: 'Where can I buy V-Guard electric motors in Nashik?', answer: 'Avegatasta Jal Urja Solutions stocks V-Guard single-phase and three-phase motors in Nashik. We can also source specific frame sizes and IE3 efficiency class motors on order. Contact us for pricing.' },
  { id: 'em-26', question: 'What is the difference between 2-pole, 4-pole, and 6-pole motors?', answer: 'Pole count determines synchronous speed: 2-pole = 3000 RPM, 4-pole = 1500 RPM, 6-pole = 1000 RPM (at 50 Hz). Choose based on the required output shaft speed for your application.' },
];

export const faqs: Record<FaqCategory, FAQ[]> = {
  'heat-pumps': heatPumpFaqs,
  'solar-water-heaters': solarWaterHeaterFaqs,
  'domestic-pumps': domesticPumpFaqs,
  'pumping-segments': pumpingSegmentFaqs,
  'water-treatment': waterTreatmentFaqs,
  'swimming-pool': swimmingPoolFaqs,
  'water-heaters': waterHeaterFaqs,
  'electric-motors': electricMotorFaqs,
};

export function getFaqsByCategory(category: string): FAQ[] {
  const key = categoryFaqMap[category] as FaqCategory | undefined;
  return key ? faqs[key] : [];
}
